    function getLatestNewsData(cookieData = '') {
        $.ajax({
            url: dataUrl,
            contentType: "application/json",
            dataType: 'json',
            callbackParameter: "c",
            cache: true,
            headers: {'Cache-Control': 'max-age=10'},
            success: function (data) {
                if (data) {
